package com.example.quicklogin;

import android.content.Context;
import android.content.SharedPreferences;
import android.text.TextUtils;

public final class CredentialStore {
    private static final String PREFS_NAME = "quick_login_prefs";
    private static final String KEY_EMAIL = "key_email";
    private static final String KEY_AUTH_TOKEN = "key_auth_token";
    private static final String KEY_LOGGED_IN = "key_logged_in";

    private CredentialStore() {}

    public static void saveCredentials(Context context, String email, String authToken) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        prefs.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_AUTH_TOKEN, authToken)
                .putBoolean(KEY_LOGGED_IN, true)
                .apply();
    }

    public static boolean isLoggedIn(Context context) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        return prefs.getBoolean(KEY_LOGGED_IN, false)
                && !TextUtils.isEmpty(prefs.getString(KEY_EMAIL, null))
                && !TextUtils.isEmpty(prefs.getString(KEY_AUTH_TOKEN, null));
    }

    public static String getEmail(Context context) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        return prefs.getString(KEY_EMAIL, "");
    }

    public static String getAuthToken(Context context) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        return prefs.getString(KEY_AUTH_TOKEN, "");
    }

    public static void clear(Context context) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        prefs.edit().clear().apply();
    }
}

package com.example.quicklogin;

import android.content.Context;
import android.os.AsyncTask;
import android.text.TextUtils;

import java.io.IOException;

public class AuthManager {

    public interface LoginCallback {
        void onSuccess(String email, String authToken);
        void onError(String message);
    }

    public void login(final Context context, final String email, final String password, final LoginCallback callback) {
        if (TextUtils.isEmpty(email) || TextUtils.isEmpty(password)) {
            if (callback != null) callback.onError("Email and password are required.");
            return;
        }

        new AsyncTask<Void, Void, LoginResult>() {
            @Override
            protected LoginResult doInBackground(Void... voids) {
                try {
                    return authenticateWithServer(email, password);
                } catch (IOException e) {
                    return LoginResult.error("Login failed: " + e.getMessage());
                }
            }

            @Override
            protected void onPostExecute(LoginResult result) {
                if (result.success) {
                    CredentialStore.saveCredentials(context, result.email, result.authToken);
                    if (callback != null) callback.onSuccess(result.email, result.authToken);
                } else {
                    if (callback != null) callback.onError(result.errorMessage);
                }
            }
        }.execute();
    }

    private LoginResult authenticateWithServer(String email, String password) throws IOException {
        if ("demo@example.com".equalsIgnoreCase(email) && "password123".equals(password)) {
            return LoginResult.success(email, "demo-token-123456");
        }
        throw new IOException("Invalid credentials");
    }

    private static class LoginResult {
        final boolean success;
        final String email;
        final String authToken;
        final String errorMessage;

        private LoginResult(boolean success, String email, String authToken, String errorMessage) {
            this.success = success;
            this.email = email;
            this.authToken = authToken;
            this.errorMessage = errorMessage;
        }

        static LoginResult success(String email, String authToken) {
            return new LoginResult(true, email, authToken, null);
        }

        static LoginResult error(String message) {
            return new LoginResult(false, null, null, message);
        }
    }
}

package com.example.quicklogin;

import android.app.Activity;
import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

public class LoginActivity extends Activity {

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;
    private TextView statusText;
    private final AuthManager authManager = new AuthManager();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (CredentialStore.isLoggedIn(this)) {
            navigateToHome();
            return;
        }

        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);
        statusText = findViewById(R.id.statusText);

        emailInput.setText(CredentialStore.getEmail(this));

        loginButton.setOnClickListener(v -> {
            String email = emailInput.getText().toString().trim();
            String password = passwordInput.getText().toString();

            loginButton.setEnabled(false);
            statusText.setText("Logging in...");

            authManager.login(this, email, password, new AuthManager.LoginCallback() {
                @Override
                public void onSuccess(String email, String authToken) {
                    loginButton.setEnabled(true);
                    statusText.setText("");
                    Toast.makeText(LoginActivity.this, "Login successful", Toast.LENGTH_SHORT).show();
                    navigateToHome();
                }

                @Override
                public void onError(String message) {
                    loginButton.setEnabled(true);
                    statusText.setText("");
                    Toast.makeText(LoginActivity.this, message, Toast.LENGTH_SHORT).show();
                }
            });
        });
    }

    private void navigateToHome() {
        Intent intent = new Intent(this, HomeActivity.class);
        startActivity(intent);
        finish();
    }
}

package com.example.quicklogin;

import android.app.Activity;
import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

public class HomeActivity extends Activity {

    private TextView welcomeText;
    private TextView tokenText;
    private Button logoutButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        welcomeText = findViewById(R.id.welcomeText);
        tokenText = findViewById(R.id.tokenText);
        logoutButton = findViewById(R.id.logoutButton);

        String email = CredentialStore.getEmail(this);
        String token = CredentialStore.getAuthToken(this);

        welcomeText.setText("Welcome, " + email);
        tokenText.setText("Auth token: " + token);

        logoutButton.setOnClickListener(v -> {
            CredentialStore.clear(this);
            Intent intent = new Intent(this, LoginActivity.class);
            intent.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP | Intent.FLAG_ACTIVITY_NEW_TASK);
            startActivity(intent);
            finish();
        });
    }
}

